/**
 * @summary List bookings for current user (mentee or mentor)
 */
export const getListMyBookingsUrl = (params?: ListMyBookingsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/bookings?${stringifiedParams}`
    : `/api/bookings`;
};

export const listMyBookings = async (
  params?: ListMyBookingsParams,
  options?: RequestInit,
): Promise<Booking[]> => {
  return customFetch<Booking[]>(getListMyBookingsUrl(params), {
    ...options,
    method: "GET",
  });
};

